using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public string TrainAndSave(string dataPath, string modelPath)
    {
        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = FormatMetrics(metrics);
        _logger.LogInformation("Evaluation metrics:\n{Report}", report);

        _mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return report;
    }

    private static string FormatMetrics(Microsoft.ML.Data.MulticlassClassificationMetrics m)
    {
        return $"""
            ┌────────────────────────────────────────┐
            │       Model Evaluation Metrics         │
            ├────────────────────────────────────────┤
            │  Macro Accuracy:  {m.MacroAccuracy,8:F4}            │
            │  Micro Accuracy:  {m.MicroAccuracy,8:F4}            │
            │  Log-Loss:        {m.LogLoss,8:F4}            │
            │  Log-Loss (Redn): {m.LogLossReduction,8:F4}            │
            └────────────────────────────────────────┘
            Per-class log-loss: {string.Join(", ", m.PerClassLogLoss.Select((v, i) => $"Class {i}: {v:F4}"))}
            """;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    public TicketClassifierController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var probabilities = new Dictionary<string, float>();
        for (var i = 0; i < Math.Min(Categories.Length, prediction.Score.Length); i++)
        {
            probabilities[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        });
    }
}

