+using Microsoft.ML;
+using TicketClassifier.Models;
+
+namespace TicketClassifier.Services;
+
+public class ModelTrainerService
+{
+    private readonly MLContext _mlContext;
+    private readonly ILogger<ModelTrainerService> _logger;
+
+    public ModelTrainerService(ILogger<ModelTrainerService> logger)
+    {
+        _mlContext = new MLContext(seed: 42);
+        _logger = logger;
+    }
+
+    public string TrainAndSave(string dataPath, string modelPath)
+    {
+        _logger.LogInformation("Loading training data from {DataPath}", dataPath);
+
+        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
+            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
+
+        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
+            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
+            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
+            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
+            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
+            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
+            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
+
+        _logger.LogInformation("Training model...");
+        var model = pipeline.Fit(split.TrainSet);
+
+        var predictions = model.Transform(split.TestSet);
+        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
+
+        var report = FormatMetrics(metrics);
+        _logger.LogInformation("Evaluation metrics:\n{Report}", report);
+
+        _mlContext.Model.Save(model, data.Schema, modelPath);
+        _logger.LogInformation("Model saved to {ModelPath}", modelPath);
+
+        return report;
+    }
