namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    public TicketClassifierController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var probabilities = new Dictionary<string, float>();
        for (var i = 0; i < Math.Min(Categories.Length, prediction.Score.Length); i++)
        {
            probabilities[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        });
    }
}

