using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

// Train the model at startup and register the pooled prediction engine
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    var trainer = new ModelTrainerService(loggerFactory.CreateLogger<ModelTrainerService>());
    trainer.TrainAndSave(dataPath, modelPath);
}

// Extract the label order from the trained model's key-value metadata
var mlContext = new MLContext();
var trainedModel = mlContext.Model.Load(modelPath, out _);
var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
trainedModel.GetOutputSchema(SchemaDefinition.Create(typeof(TicketInput)))["PredictedLabel"]
    .GetKeyValues(ref labelBuffer);
var labelNames = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

builder.Services.AddSingleton(new LabelMap { Labels = labelNames });

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

